# Custom Plug to enforce XML content type and size limits
defmodule MyAppWeb.Plugs.SoapSecurity do
  @moduledoc """
  Plug that enforces security constraints on incoming SOAP/XML requests.
  """
  import Plug.Conn

  @max_body_size 1_048_576  # 1 MB max XML body size

  def init(opts), do: opts

  def call(conn, _opts) do
    content_type = get_req_header(conn, "content-type") |> List.first() || ""

    if String.contains?(content_type, "xml") do
      case get_req_header(conn, "content-length") do
        [length_str | _] ->
          case Integer.parse(length_str) do
            {length, _} when length > @max_body_size ->
              conn
              |> put_resp_content_type("text/xml")
              |> send_resp(413, "<error>Request body too large</error>")
              |> halt()

            _ ->
              conn
          end

        _ ->
          conn
      end
    else
      conn
    end
  end
end